template <typename SUBNET> using block_a3 = relu<con<10,3,3,1,1,relu<con<16,1,1,1,1,SUBNET>>>>;

Could you please explain why does the change of the size in conv layer leads to the crash issue ?
What is incorrectly used ?

[utilities.py](https://github.com/lawsie/guizero/blob/dev/guizero/utilities.py):

# Lambda-izer for making it easy to pass arguments with function calls
# without having to know what lambda does
def with_args( func_name, *args):
    return lambda: func_name(*args)

Instead of `with_args`, we could use [`functools.partial`](https://docs.python.org/3/library/functools.html#functools.partial), which does the same thing, but is easier to extend.

Similar to https://github.com/myint/cppclean/issues/72 a token exception is raised when parsing a C++11 std::function. See below for error message and code example.

#### Error message
>Got exception in MyClass.h @ Token('std', 92, 95) []
>Got exception in MyClass.h @ Token('class', 37, 42) []
>MyClass.h: parsing error (Token('>', 126, 127), [Token('std', 92, 95), Token('::', 95, 97), Token('function', 97, 105), Token('<', 105, 106)], [Token('double', 111, 117), Token(',', 117, 118), Token('double', 119, 125)])

#### Code example
````cpp
#pragma once

#include <functional>

class CMyClass
{
public:
  CMyClass();
    
private:
  std::function<void(double, double)> mFunctor;
};
````

import asn1crypto.core
import unittest

class SpcPeImageFlags(asn1crypto.core.BitString):
    _map = {
    0 : "includeResources",
    1 : "includeDebugInfo",    
    2 : "includeImportAddressTable",
    }

class SpcSerializedObject(asn1crypto.core.Sequence):
    _fields = [
        ("classId", asn1crypto.core.OctetString),
        ("serializedData", asn1crypto.core.OctetString),
    ]

class SpcString(asn1crypto.core.Choice):
    _alternatives = [
        ("unicode", asn1crypto.core.BMPString, {"implicit": 0}),
        ("ascii", asn1crypto.core.IA5String, {"implicit": 1}),
    ]

class SpcLink(asn1crypto.core.Choice):
    _alternatives = [
        ("url", asn1crypto.core.IA5String, {"implicit": 0}),
        ("moniker", SpcSerializedObject, {"implicit": 1}),
        ("file", SpcString, {"explicit": 2})
    ]

class SpcPeImageData(asn1crypto.core.Sequence):
    _fields = [
        ("flags",SpcPeImageFlags,{"default":"includeResources"}),
        ("file",SpcLink,{"explicit": 0})
    ]


class CoreTests(unittest.TestCase):
    def test_what_problem(self):
        bytes_piece = b"\x30\x09\x03\x01\x00\xA0\x04\xA2\x02\x80\x00"
        asn_piece = SpcPeImageData.load(bytes_piece, strict=True)
        self.assertEqual(bytes_piece[2:5], 
            asn_piece['flags'].dump())
        self.assertEqual(bytes_piece[5:11], 
            asn_piece['file'].dump())

